# Python 3.11+
"""Domain vocabulary for the resource pool: the resource state machine, the
typed error hierarchy, and the entity that wraps one poolable resource.

A pool hands out a FIXED set of expensive-to-create resources (DB connections,
sockets, worker handles) and takes them back. The only stateful noun is the
resource itself — it cycles IDLE -> IN_USE -> IDLE, and may be CLOSED at the end.
"""

from dataclasses import dataclass, field
from enum import Enum


class ResourceState(Enum):
    """Where one pooled resource is in its borrow/return lifecycle."""

    IDLE = "IDLE"        # in the pool, free to hand out
    IN_USE = "IN_USE"    # checked out by a caller
    CLOSED = "CLOSED"    # destroyed; never handed out again


# ── error hierarchy: ONE base, one subclass per failure mode ───────────────────
class PoolError(Exception):
    """Base for every pool failure. Callers can catch this to catch them all."""


class InvalidPoolConfigError(PoolError):
    """max_size <= 0, or a missing factory — the pool can't be built."""


class PoolExhaustedError(PoolError):
    """All resources are checked out and the acquire timed out (or was non-blocking)."""


class PoolClosedError(PoolError):
    """acquire/release after the pool was shut down."""


class ResourceNotFromPoolError(PoolError):
    """release() was handed an object this pool never created."""


class ResourceAlreadyReturnedError(PoolError):
    """release() was called on a resource that is not currently IN_USE (double-return)."""


@dataclass
class PooledResource:
    """One borrowable resource. Owns its OWN state transitions — the pool never
    reaches in and flips `state` by hand; it calls these methods, so the legal
    transitions live in exactly one place (Information Expert).

    `payload` is the real underlying thing (a connection object); the pool treats
    it as opaque. `id` is a stable handle for logging and equality.
    """

    id: int
    payload: object
    state: ResourceState = field(default=ResourceState.IDLE)

    def mark_in_use(self) -> None:
        if self.state is not ResourceState.IDLE:
            raise ResourceAlreadyReturnedError(
                f"resource {self.id} is {self.state.value}, cannot hand out"
            )
        self.state = ResourceState.IN_USE

    def mark_idle(self) -> None:
        if self.state is not ResourceState.IN_USE:
            raise ResourceAlreadyReturnedError(
                f"resource {self.id} is {self.state.value}, cannot return"
            )
        self.state = ResourceState.IDLE

    def close(self) -> None:
        # Idempotent terminal transition: closing a closed resource is a no-op.
        self.state = ResourceState.CLOSED

    @property
    def is_idle(self) -> bool:
        return self.state is ResourceState.IDLE

