import threading, time, itertools, random
import sys
sys.path.insert(0,'.')
from thread_safe_pool import ThreadSafeResourcePool
from models import PoolExhaustedError, PoolClosedError

# Aggressive stampede with no sleep (try to catch races), many iterations
def factory():
    c=itertools.count(1)
    return lambda: f"c-{next(c)}"

violations=[]
for trial in range(40):
    CAP=4; N=40
    p=ThreadSafeResourcePool(factory(),CAP)
    barrier=threading.Barrier(N)
    guard=threading.Lock()
    state={'peak':0,'served':0}
    def worker():
        barrier.wait()
        for _ in range(20):
            try:
                with p.lease(timeout=5) as r:
                    with guard:
                        state['served']+=1
                        cur=p.in_use_count
                        if cur>CAP: violations.append((trial,cur))
                        state['peak']=max(state['peak'],cur)
            except PoolExhaustedError:
                violations.append(('timeout',trial))
    ts=[threading.Thread(target=worker) for _ in range(N)]
    for t in ts: t.start()
    for t in ts: t.join()
    if p.in_use_count!=0: violations.append(('leak-inuse',trial,p.in_use_count))
    # gate permits should be back to CAP
    if p._gate._value != CAP: violations.append(('gate-permits',trial,p._gate._value))
print('peak last trial:', state['peak'], 'CAP', CAP)
print('violations:', violations[:20], 'total', len(violations))
print('OK' if not violations else 'FOUND ISSUES')
