# Factory that fails the first 2 times then succeeds (transient outage)
state={'n':0}
def flaky():
    state['n']+=1
    if state['n'] <= 2:
        raise RuntimeError("transient connect failure")
    return f"conn-{state['n']}"

p = ThreadSafeResourcePool(flaky, max_size=2)
for i in range(2):
    try:
        p.acquire(timeout=0.5)
    except RuntimeError as e:
        print(f"attempt {i}: factory failed, permits now = {p._gate._value}")

print("After 2 transient failures: permits =", p._gate._value, "(should be 2)")
# Now the outage is over. Try to acquire 2 good resources:
try:
    a = p.acquire(timeout=0.5)
    print("acquired a:", a.payload)
    b = p.acquire(timeout=0.5)
    print("acquired b:", b.payload)
